-    components/
-      Nav.astro               # Responsive nav with hamburger
-      Footer.astro
-      BlogCard.astro
-      DirectorCard.astro
-      FeedbackForm.astro
-      MissionPillarCard.astro
-      BlogHighlight.astro     # Client-side island: fetches /api/recent-posts
